(* CoreTerm — kernel calculus syntax (mirror of *)
(* `verum_kernel::CoreTerm` at term.rs:31-377). *)
Inductive CoreTerm : Type :=
  | Var (name : string)
  | Universe (level : nat)
  | Pi (binder : string) (domain codomain : CoreTerm)
  | Lam (binder : string) (domain body : CoreTerm)
  | App (head arg : CoreTerm)
  | Sigma (binder : string) (fst_ty snd_ty : CoreTerm)
  | Pair (fst snd : CoreTerm)
  | Fst (inner : CoreTerm)
  | Snd (inner : CoreTerm)
  | PathTy (carrier lhs rhs : CoreTerm)
  | PathOver (motive path lhs rhs : CoreTerm)
  | Refl (value : CoreTerm)
  | HComp (phi walls base : CoreTerm)
  | Transp (path regular value : CoreTerm)
  | Glue (carrier phi fiber equiv : CoreTerm)
  | Refine (base : CoreTerm) (binder : string) (predicate : CoreTerm)
  | Quotient (base equiv : CoreTerm)
  | QuotIntro (value base equiv : CoreTerm)
  | QuotElim (scrutinee motive case_fn : CoreTerm)
  | Inductive_ (path : string) (args : list CoreTerm)
  | Elim (scrutinee motive : CoreTerm) (cases : list CoreTerm)
  | SmtProof (solver_tag : string)
  | Axiom_ (name : string) (ty : CoreTerm) (framework : string)
  | EpsilonOf (articulation : CoreTerm)
  | AlphaOf (enactment : CoreTerm)
  | ModalBox (inner : CoreTerm)
  | ModalDiamond (inner : CoreTerm)
  | ModalBigAnd (components : list CoreTerm)
  | Shape (inner : CoreTerm)
  | Flat (inner : CoreTerm)
  | Sharp (inner : CoreTerm).

(* CoreType — structural type-head view (mirror of *)
(* `verum_kernel::CoreType` at term.rs:386-403). *)
Inductive CoreType : Type :=
  | UniverseTy (level : nat)
  | PiTy
  | SigmaTy
  | PathTyHead
  | RefineTy
  | GlueTy
  | InductiveTy (path : string)
  | OtherTy.

(* KernelRule — the 35 inference-rule names. *)
Inductive KernelRule : Type :=
    | K_Var
    | K_Univ
    | K_Pi_Form
    | K_Lam_Intro
    | K_App_Elim
    | K_Sigma_Form
    | K_Pair_Intro
    | K_Fst_Elim
    | K_Snd_Elim
    | K_Path_Ty_Form
    | K_Path_Over_Form
    | K_Refl_Intro
    | K_HComp
    | K_Transp
    | K_Glue
    | K_Refine
    | K_Refine_Omega
    | K_Refine_Intro
    | K_Refine_Erase
    | K_Quot_Form
    | K_Quot_Intro
    | K_Quot_Elim
    | K_Inductive
    | K_Pos
    | K_Elim
    | K_Smt
    | K_FwAx
    | K_Eps_Mu
    | K_Universe_Ascent
    | K_Round_Trip
    | K_Epsilon_Of
    | K_Alpha_Of
    | K_Modal_Box
